mapper.select:
SELECT COUNT(*)
FROM lecture
WHERE member_code = #{memberCode}
AND is_del = false
AND status = #{req.status}

    AND lecture_name LIKE CONCAT('%', #{req.lectureName}, '%')

AND year = #{req.year}
AND semester = #{req.semester}

SELECT COUNT(DISTINCT l.lecture_id)
FROM course c
JOIN lecture l ON c.lecture_id = l.lecture_id
WHERE c.student_code = #{memberCode}
AND l.status = 'APPROVED'
AND l.year = #{req.year}
AND l.semester = #{req.semester}


        AND c.created_at < #{req.createdBefore}
        AND (c.is_del = false OR c.deleted_at >= #{req.createdBefore})


        AND c.is_del = false

SELECT COUNT(DISTINCT l.lecture_id)
FROM lecture l
LEFT JOIN professor_cache pc ON l.member_code = pc.member_code
WHERE l.status = 'APPROVED'
AND l.year = #{year}
AND l.year != 9999

    AND (

        l.lecture_name LIKE CONCAT('%', #{lectureName}, '%')


        OR pc.name LIKE CONCAT('%', #{proName}, '%')

    )

AND l.major_id = #{majorId}
AND l.semester = #{semester}

SELECT l.lecture_id AS lectureId, l.member_code AS memberCode, l.major_id AS majorId, mj.name AS majorName, pc.name AS proName, l.year, l.semester, l.lecture_name AS lectureName, l.credit, l.lecture_type AS lectureType, l.ref_books AS refBooks, l.goal, l.weekly_plan AS weeklyPlan, l.academic_year AS academicYear, l.start_date AS startDate, l.end_date AS endDate,
FROM lecture l LEFT JOIN major mj ON l.major_id = mj.major_id LEFT JOIN professor_cache pc ON l.member_code = pc.member_code
WHERE l.lecture_id = #{lectureId}
